SELECT status, COUNT(*) AS count
FROM command_status
GROUP BY status;

SELECT status
FROM command_status
WHERE command_id = 0;

SELECT status
FROM command_status
WHERE status_id IN (0, 1);

SELECT name
FROM contexts
WHERE unique_topic = 1;

SELECT COUNT(*) AS command_count
FROM command_status
WHERE user_id = 1;

SELECT user_name
FROM users
WHERE user_id IN (SELECT DISTINCT created_by FROM commands);

SELECT command_name, created_at
FROM commands
ORDER BY created_at ASC;
